-- Create "ova_template_families" table
CREATE TABLE "ova_template_families" ("id" uuid NOT NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "type" character varying NOT NULL, "description" character varying NOT NULL DEFAULT '', "tools" jsonb NULL, "skills" jsonb NULL, "scenarios" jsonb NULL, "icon_shape" character varying NOT NULL DEFAULT '', "icon_color" character varying NOT NULL DEFAULT 'BLUE', PRIMARY KEY ("id"));
-- Create "ova_template_versions" table
CREATE TABLE "ova_template_versions" ("id" uuid NOT NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "version" character varying NOT NULL, "ova_identifier" character varying NOT NULL, "notes" character varying NULL, "ova_template_family_versions" uuid NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "ova_template_versions_ova_template_families_versions" FOREIGN KEY ("ova_template_family_versions") REFERENCES "ova_template_families" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
